import { useTranslations } from "next-intl";
import { IPhoneMock } from "./iphone-mock";

interface ChatMessage {
  text: string;
  from: "user" | "bot";
}

export function PhoneMockup({ className = "" }: { className?: string }) {
  const t = useTranslations("PhoneMockup");

  const messages: ChatMessage[] = [
    { from: "user", text: t("msg1") },
    { from: "bot", text: t("msg2") },
    { from: "user", text: t("msg3") },
    { from: "bot", text: t("msg4") },
  ];

  return (
    <IPhoneMock className={className}>
      <div className="flex h-full flex-col bg-[#050505] px-5 pt-18 pb-6 text-white">
        <div className="border-b border-white/8 px-4 pb-4 text-center">
          <div className="mx-auto mb-2 flex h-10 w-10 items-center justify-center rounded-full bg-imessage">
            <span className="text-sm font-bold text-white">C</span>
          </div>
          <p className="text-[13px] font-semibold text-white">{t("header")}</p>
        </div>

        <div className="flex flex-1 flex-col gap-3 px-2 pt-4">
          {messages.map((msg, i) => (
            <div
              key={i}
              className={`flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
            >
              <div
                className={`max-w-[84%] rounded-[22px] px-4 py-2.5 text-[13px] leading-[1.45] whitespace-pre-line ${
                  msg.from === "user"
                    ? "bg-imessage text-white"
                    : "bg-[#2a2a2c] text-white"
                }`}
              >
                {msg.text}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-4 flex items-center gap-3 rounded-full border border-white/10 bg-black/40 px-4 py-2.5">
          <div className="h-5 w-5 rounded-full bg-white/10" />
          <span className="flex-1 text-[12px] text-white/40">
            {t("inputPlaceholder")}
          </span>
          <div className="flex h-6 w-6 items-center justify-center rounded-full bg-imessage">
            <svg
              width="11"
              height="11"
              viewBox="0 0 24 24"
              fill="white"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path d="M3.4 20.4l17.45-7.48a1 1 0 000-1.84L3.4 3.6a1 1 0 00-1.39.91L2 9.12a1 1 0 00.9 1l10.13 1.12L2.9 12.36a1 1 0 00-.9 1l.01 5.12a1 1 0 001.39.92z" />
            </svg>
          </div>
        </div>
      </div>
    </IPhoneMock>
  );
}

export function MiniChat({
  messages,
  className = "",
}: {
  messages: ChatMessage[];
  className?: string;
}) {
  return (
    <div className={`rounded-2xl bg-black p-3 ${className}`}>
      <div className="flex flex-col gap-1.5">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={`flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
          >
            <div
              className={`max-w-[85%] rounded-xl px-3 py-1.5 text-[11px] leading-[1.4] whitespace-pre-line ${
                msg.from === "user"
                  ? "bg-imessage text-white"
                  : "bg-[#2a2a2c] text-white"
              }`}
            >
              {msg.text}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
